-- 4.4.2 Группа оценки внешнеэкономической деятельности клиентов
WITH ins AS (
  INSERT INTO t_p61016064_digital_innovation_i.dept_functions (project_id, dept_name, title, category, source_section_code)
  SELECT 1, 'Департамент финансового мониторинга (ДФМ)', v.title, v.category, '4.4.2'
  FROM (VALUES
    ('Обеспечение своевременного выявления подозрительных операций (сделок), связанных с легализацией (отмыванием) доходов, полученных преступным путём, или финансированием терроризма, совокупности подозрительных операций и (или) действий при осуществлении клиентами внешнеэкономической деятельности','control'),
    ('Разработка программ и процедур, направленных на выявление и предотвращение необычных операций (сделок) при осуществлении клиентами внешнеэкономической деятельности, которые могут привести к потере Банком своей деловой репутации или иным правовым и финансовым рискам, в части, касающейся деятельности Группы оценки внешнеэкономической деятельности клиентов','methodology'),
    ('Осуществление выявления новых типов сомнительных финансовых схем при осуществлении клиентами внешнеэкономической деятельности, направленного на легализацию преступных доходов, финансирование терроризма или финансирование распространения оружия массового уничтожения','analytical'),
    ('Осуществление согласования платежей клиентов при осуществлении клиентами внешнеэкономической деятельности с признаками сомнительности','control'),
    ('Осуществление профилактики подозрительной активности в деятельности клиентов, осуществляющих внешнеэкономические операции, во взаимодействии с обслуживающими клиентов ГОЗ структурными бизнес-подразделениями Банка','control'),
    ('Осуществление консультирования работников УФМ СЦ по вопросам формирования сообщений о подозрительных операциях в целях обеспечения неукоснительного соблюдения ими требований законодательства Российской Федерации и нормативных актов Банка России в сфере ПОД/ФТ','communication')
  ) AS v(title, category)
  RETURNING id, source_section_code
)
INSERT INTO t_p61016064_digital_innovation_i.function_org_units (function_id, org_unit_id, role, source_ref)
SELECT ins.id, u.id, 'owner', 'polozhenie'
FROM ins JOIN t_p61016064_digital_innovation_i.org_units u
  ON u.project_id = 1 AND u.code = '4.4.2' AND u.is_archived = false;

-- 4.4.3 Группа оценки потенциальных клиентов
WITH ins2 AS (
  INSERT INTO t_p61016064_digital_innovation_i.dept_functions (project_id, dept_name, title, category, source_section_code)
  SELECT 1, 'Департамент финансового мониторинга (ДФМ)', v.title, v.category, '4.4.3'
  FROM (VALUES
    ('Обеспечение своевременного рассмотрения заявок при приёме потенциальных клиентов на обслуживание','control'),
    ('Разработка программ и процедур, направленных на выявление и предотвращение проникновения в Банк подозрительных потенциальных клиентов, деятельность которых может привести к потере Банком деловой репутации или иным правовым и финансовым рискам, в части, касающейся деятельности Группы оценки потенциальных клиентов','methodology'),
    ('Осуществление выявления новых категорий высокорисковых потенциальных клиентов и инициирование разработки автоматизированных инструментов выявления таких категорий клиентов при приёме на обслуживание','analytical'),
    ('Осуществление консультирования работников Банка по вопросам проверки потенциальных клиентов при приёме на обслуживание в целях обеспечения неукоснительного соблюдения ими требований законодательства Российской Федерации и нормативных актов Банка России в сфере ПОД/ФТ','communication')
  ) AS v(title, category)
  RETURNING id, source_section_code
)
INSERT INTO t_p61016064_digital_innovation_i.function_org_units (function_id, org_unit_id, role, source_ref)
SELECT ins2.id, u.id, 'owner', 'polozhenie'
FROM ins2 JOIN t_p61016064_digital_innovation_i.org_units u
  ON u.project_id = 1 AND u.code = '4.4.3' AND u.is_archived = false;